import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

public class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    public void testParse_ReturnsCSVParserInstance() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // do nothing, default mock behavior
                })) {

            CSVFormat format = CSVFormat.DEFAULT;
            CSVParser parser = format.parse(mockReader);

            assertNotNull(parser);
            assertTrue(parser instanceof CSVParser);

            // verify CSVParser constructor called with correct parameters
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(parser, constructedParser);
        }
    }

    @Test
    public void testParse_NullReader_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }

}
